import{_ as t,o,c as r,ag as i}from"./chunks/framework.CbQjVMS6.js";const a="/assets/gitmerge.Bucog4ir.png",u=JSON.parse('{"title":"Decompile 8XP Programs to Plain Text TI Basic","description":"","frontmatter":{},"headers":[],"relativePath":"features/decompile-8xp.md","filePath":"features/decompile-8xp.md","lastUpdated":1774323326000}'),s={name:"features/decompile-8xp.md"};function p(l,e,c,n,d,h){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="decompile-8xp-programs-to-plain-text-ti-basic" tabindex="-1">Decompile 8XP Programs to Plain Text TI Basic <a class="header-anchor" href="#decompile-8xp-programs-to-plain-text-ti-basic" aria-label="Permalink to &quot;Decompile 8XP Programs to Plain Text TI Basic&quot;">​</a></h1><p>Every time you run <code>Powerpack.exe</code> to process/optimize your 8XP program, it needs to decompile the 8XP binary into plain text source code for processing. Powerpack will also save a copy of this plain text code.</p><p>Look for the subfolder called <code>Source Code as Text</code> in the same folder as your 8XP program. You’ll see three files:</p><table tabindex="0"><thead><tr><th>File</th><th>Description</th></tr></thead><tbody><tr><td><code>YOURPROG.8xp-source</code></td><td>A copy of the original source code in plain text</td></tr><tr><td><code>YOURPROG.optimized.8xp-source</code></td><td>A plain text version of the “optimized” code, after Powerpack has processed it, where all comments and extraneous characters have been removed</td></tr><tr><td><code>YOURPROG.optimized.8xp-byte-counts</code></td><td>A <a href="/features/file-size-reports">file size report</a> showing the number of bytes used on each line</td></tr></tbody></table><hr><p>This is useful if you want to:</p><ul><li><p>Extract the code from an 8XP program for use elsewhere</p></li><li><p>Compare multiple versions of a program using a text comparison tool like <a href="https://winmerge.org/" target="_blank" rel="noreferrer">WinMerge</a></p></li><li><p>Keep track of your code changes using git or other version control mechanism</p></li></ul><p><img src="'+a+'" alt=""></p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Do NOT make changes to the files in <code>Source Code as Text</code> unless you move them to another location. Otherwise they will be overwritten the next time you run Powerpack on your original program.</p></div><h2 id="file-size-report" tabindex="-1">File size report <a class="header-anchor" href="#file-size-report" aria-label="Permalink to &quot;File size report&quot;">​</a></h2><p>The third file ending in <code>.optimized.8xp-byte-counts</code> helps you identify the number of bytes used throughout each line of the file, and the total.</p><p>See <a href="/features/file-size-reports">File size reports</a></p>',12)])])}const f=t(s,[["render",p]]);export{u as __pageData,f as default};
